properties.entry:
PROVENANCE WITH SEMIRING COMBINER VITERBI OF (
  SELECT c.b
  FROM R_f HAS PROVENANCE (f) a, R_f HAS PROVENANCE (f) b, R_f HAS PROVENANCE (f) c
  WHERE a.b = b.a AND b.b = c.a AND a.a = 1
);

PROVENANCE WITH SEMIRING COMBINER VITERBI OF (
  SELECT a.a, c.b
  FROM R_f HAS PROVENANCE (f) a, R_f HAS PROVENANCE (f) b, R_f HAS PROVENANCE (f) c
  WHERE a.b = b.a AND b.b = c.a
);

PROVENANCE WITH SEMIRING COMBINER VITERBI OF (
  SELECT 1
  FROM R_f HAS PROVENANCE (f) a, R_f HAS PROVENANCE (f) b, R_f HAS PROVENANCE (f) c
  WHERE a.b = b.a AND b.b = c.a
);
